        `],glossary:[{term:"Evaluaci\xF3n Heur\xEDstica",definition:"Inspecci\xF3n de usabilidad realizada por expertos frente a heur\xEDsticas de dise\xF1o.",analogy:"Lista de control de seguridad para un autom\xF3vil antes de salir."},{term:"Dise\xF1o Iterativo",definition:"Ciclos repetidos de boceto, test de usabilidad y refinamiento incremental.",analogy:"Esculpir en arcilla pidiendo retroalimentaci\xF3n continua."}]},{code:"Q9-13",title:"Inteligencia Artificial y Arduino",shortDesc:"Redes neuronales con TensorFlow, TensorFlow Lite en microcontroladores, clasificaci\xF3n de formas y l\xF3gica de hardware.",purposeUsability:"Habilitar inteligencia embebida en hardware local (TinyML/Edge AI) sin depender de servidores externos.",context:"Ejecuci\xF3n de inferencia neuronal en microcontroladores de memoria reducida.",complexity:"Alta. Redes neuronales, cuantificaci\xF3n INT8 y visi\xF3n artificial con OpenCV.",theory:[`
